    @Override
    public SOAPMessage invoke(SOAPMessage request) {
        try {
            LOGGER.info("Received SOAP request");
            SOAPBody requestBody = request.getSOAPBody();

            Document doc = parseSOAPBodyToDocument(requestBody);
            if (doc == null) {
                return createErrorResponse("Failed to parse request body");
            }

            String operation = detectOperation(doc);
            LOGGER.info("Detected operation: " + operation);

            switch (operation) {
                case "DataImport":
                    return handleDataImport(doc);
                case "BatchProcess":
                    return handleBatchProcess(doc);
                case "EntitySync":
                    return handleEntitySync(doc);
                case "StatusQuery":
                    return handleStatusQuery(doc);
                default:
                    return createErrorResponse("Unknown operation: " + operation);
            }

        } catch (SOAPException e) {
            LOGGER.log(Level.SEVERE, "SOAP processing error", e);
            try {
                return createErrorResponse("SOAP processing error: " + e.getMessage());
            } catch (Exception ex) {
                throw new RuntimeException(ex);
            }
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Unexpected error", e);
            try {
                return createErrorResponse("Internal error: " + e.getMessage());
            } catch (Exception ex) {
                throw new RuntimeException(ex);
            }
        }
    }

    private Document parseSOAPBodyToDocument(SOAPBody soapBody) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            // Security: Disable external entities to prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();

            // Convert SOAPBody content to a standalone Document
            TransformerFactory tf = TransformerFactory.newInstance();
            Transformer transformer = tf.newTransformer();
            StringWriter writer = new StringWriter();

            NodeList children = soapBody.getChildNodes();
            StringBuilder xmlContent = new StringBuilder("<?xml version=\"1.0\" encoding=\"UTF-8\"?><RequestWrapper>");
            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    transformer.transform(new DOMSource(child), new StreamResult(writer));
                    xmlContent.append(writer.toString().replaceFirst("<\\?xml[^?]*\\?>", ""));
                    writer.getBuffer().setLength(0);
                }
            }
            xmlContent.append("</RequestWrapper>");

            return builder.parse(new InputSource(new StringReader(xmlContent.toString())));
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Document parsing failed", e);
            return null;
        }
    }

    public Document parseXMLString(String xmlContent) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new InputSource(new StringReader(xmlContent)));
    }

    private String detectOperation(Document doc) {
        Element root = doc.getDocumentElement();
        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                String localName = child.getLocalName() != null ? child.getLocalName() : child.getNodeName();
                if (localName.contains("Import") || localName.contains("import")) return "DataImport";
                if (localName.contains("Batch") || localName.contains("batch")) return "BatchProcess";
                if (localName.contains("Sync") || localName.contains("sync")) return "EntitySync";
                if (localName.contains("Status") || localName.contains("status")) return "StatusQuery";
            }
        }
        return "DataImport"; // default
    }

    // --- Data Import Handler ---
    private SOAPMessage handleDataImport(Document doc) throws Exception {
        LOGGER.info("Processing Data Import request");

        String jobId = UUID.randomUUID().toString();
        ImportJob job = new ImportJob(jobId, "DataImport");
        activeJobs.put(jobId, job);

        List<DataEntity> entities = extractEntities(doc.getDocumentElement());
        job.setTotalRecords(entities.size());
        LOGGER.info("Extracted " + entities.size() + " entities for import");

        // Process in batches for large payloads
        int batchSize = 100;
        List<Future<BatchResult>> futures = new ArrayList<>();

        for (int i = 0; i < entities.size(); i += batchSize) {
            int end = Math.min(i + batchSize, entities.size());
            List<DataEntity> batch = entities.subList(i, end);
            int batchNum = (i / batchSize) + 1;

            futures.add(processingPool.submit(() -> processBatch(batch, batchNum, job)));
        }

        // Collect results
        int successCount = 0;
        int failCount = 0;
        List<String> errors = new ArrayList<>();

        for (Future<BatchResult> future : futures) {
            try {
                BatchResult result = future.get(60, TimeUnit.SECONDS);
                successCount += result.successCount;
                failCount += result.failCount;
                errors.addAll(result.errors);
            } catch (TimeoutException e) {
                failCount++;
                errors.add("Batch processing timed out");
            } catch (ExecutionException e) {
                failCount++;
                errors.add("Batch processing failed: " + e.getCause().getMessage());
            }
        }

        job.setProcessedRecords(successCount);
        job.setFailedRecords(failCount);
        job.setStatus("COMPLETED");
        job.setErrors(errors);

        return createImportResponse(jobId, successCount, failCount, errors);
    }

    // --- Batch Process Handler ---
    private SOAPMessage handleBatchProcess(Document doc) throws Exception {
        LOGGER.info("Processing Batch request");

        String jobId = UUID.randomUUID().toString();
        ImportJob job = new ImportJob(jobId, "BatchProcess");
        activeJobs.put(jobId, job);

        NodeList batchNodes = doc.getElementsByTagName("*");
        List<Map<String, String>> records = new ArrayList<>();

        for (int i = 0; i < batchNodes.getLength(); i++) {
            Node node = batchNodes.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                String name = node.getLocalName() != null ? node.getLocalName() : node.getNodeName();
                if (name.equalsIgnoreCase("Record") || name.equalsIgnoreCase("Item")) {
                    Map<String, String> record = extractFlatRecord((Element) node);
                    records.add(record);
                }
            }
        }

        job.setTotalRecords(records.size());
        LOGGER.info("Batch contains " + records.size() + " records");

        int processed = 0;
        List<String> errors = new ArrayList<>();
        for (Map<String, String> record : records) {
            try {
                processRecord(record);
                processed++;
            } catch (Exception e) {
                errors.add("Record processing failed: " + e.getMessage());
            }
        }

        job.setProcessedRecords(processed);
        job.setFailedRecords(records.size() - processed);
        job.setStatus("COMPLETED");

        return createImportResponse(jobId, processed, records.size() - processed, errors);
    }

    // --- Entity Sync Handler ---
    private SOAPMessage handleEntitySync(Document doc) throws Exception {
        LOGGER.info("Processing Entity Sync request");

        String jobId = UUID.randomUUID().toString();
        ImportJob job = new ImportJob(jobId, "EntitySync");
        activeJobs.put(jobId, job);

        List<DataEntity> entities = extractEntities(doc.getDocumentElement());
        job.setTotalRecords(entities.size());

        int synced = 0;
        int conflicts = 0;
        List<String> syncResults = new ArrayList<>();

        for (DataEntity entity : entities) {
            try {
                SyncResult result = syncEntity(entity);
                if (result.isConflict) {
                    conflicts++;
                    syncResults.add("Conflict on entity: " + entity.getId() + " - " + result.message);
                } else {
                    synced++;
                }
            } catch (Exception e) {
                syncResults.add("Sync failed for entity: " + entity.getId() + " - " + e.getMessage());
            }
        }

        job.setProcessedRecords(synced);
        job.setFailedRecords(conflicts);
        job.setStatus("COMPLETED");

        return createSyncResponse(jobId, synced, conflicts, syncResults);
    }

    // --- Status Query Handler ---
    private SOAPMessage handleStatusQuery(Document doc) throws Exception {
        LOGGER.info("Processing Status Query");

        String queryJobId = null;
        NodeList nodes = doc.getElementsByTagName("*");
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            String name = node.getLocalName() != null ? node.getLocalName() : node.getNodeName();
            if (name.equalsIgnoreCase("JobId") || name.equalsIgnoreCase("jobId")) {
                queryJobId = node.getTextContent().trim();
                break;
            }
        }

        if (queryJobId != null && activeJobs.containsKey(queryJobId)) {
            ImportJob job = activeJobs.get(queryJobId);
            return createStatusResponse(job);
        } else {
            return createErrorResponse("Job not found: " + queryJobId);
        }
    }

    // --- Entity Extraction (handles complex nested structures) ---
    private List<DataEntity> extractEntities(Element root) {
        List<DataEntity> entities = new ArrayList<>();
        extractEntitiesRecursive(root, entities, null, 0);
        return entities;
    }

    private void extractEntitiesRecursive(Element element, List<DataEntity> entities, DataEntity parent, int depth) {
        if (depth > 50) {
            LOGGER.warning("Maximum nesting depth reached, skipping deeper elements");
            return;
        }

        String tagName = element.getLocalName() != null ? element.getLocalName() : element.getNodeName();

        // Check if this element represents a data entity
        if (isEntityElement(element)) {
            DataEntity entity = new DataEntity();
            entity.setId(extractAttribute(element, "id", "entityId", "ID"));
            entity.setType(tagName);
            entity.setParent(parent);

            // Extract attributes
            NamedNodeMap attrs = element.getAttributes();
            for (int i = 0; i < attrs.getLength(); i++) {
                Attr attr = (Attr) attrs.item(i);
                entity.addAttribute(attr.getName(), attr.getValue());
            }

            // Extract child elements
            NodeList children = element.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    Element childElement = (Element) child;
                    if (isEntityElement(childElement)) {
                        // Nested entity
                        extractEntitiesRecursive(childElement, entities, entity, depth + 1);
                    } else if (isLeafElement(childElement)) {
                        // Simple property
                        String key = childElement.getLocalName() != null ? childElement.getLocalName() : childElement.getNodeName();
                        String value = childElement.getTextContent().trim();
                        entity.addProperty(key, value);
                    } else {
                        // Complex property - flatten or store as nested map
                        Map<String, String> nestedProps = flattenElement(childElement, tagName);
                        entity.getProperties().putAll(nestedProps);
                    }
                }
            }

            entities.add(entity);
            if (parent != null) {
                parent.addChild(entity);
            }
        } else {
            // Not an entity, traverse children
            NodeList children = element.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                Node child = children.item(i);
                if (child.getNodeType() == Node.ELEMENT_NODE) {
                    extractEntitiesRecursive((Element) child, entities, parent, depth + 1);
                }
            }
        }
    }

    private boolean isEntityElement(Element element) {
        String tagName = element.getLocalName() != null ? element.getLocalName() : element.getNodeName();
        // An element is considered an entity if it has an id attribute or matches common patterns
        if (element.hasAttribute("id") || element.hasAttribute("entityId") || element.hasAttribute("ID")) {
            return true;
        }
        String[] entityPatterns = {"Entity", "Record", "Item", "Customer", "Order", "Product",
                "Employee", "Account", "Transaction", "Invoice", "LineItem",
                "Address", "Contact", "Department", "Organization"};
        for (String pattern : entityPatterns) {
            if (tagName.toLowerCase().contains(pattern.toLowerCase())) {
                return true;
            }
        }
        // If it has multiple child elements, it might be a container or entity
        int childElementCount = 0;
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                childElementCount++;
            }
        }
        return childElementCount >= 3;
    }

    private boolean isLeafElement(Element element) {
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                return false;
            }
        }
        return true;
    }

    private Map<String, String> flattenElement(Element element, String prefix) {
        Map<String, String> result = new LinkedHashMap<>();
        String tagName = element.getLocalName() != null ? element.getLocalName() : element.getNodeName();
        String currentPrefix = prefix != null ? prefix + "." + tagName : tagName;

        NodeList children = element.getChildNodes();
        boolean hasChildElements = false;

        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                hasChildElements = true;
                Element childElement = (Element) child;
                if (isLeafElement(childElement)) {
                    String key = childElement.getLocalName() != null ? childElement.getLocalName() : childElement.getNodeName();
                    result.put(currentPrefix + "." + key, childElement.getTextContent().trim());
                } else {
                    result.putAll(flattenElement(childElement, currentPrefix));
                }
            }
        }

        if (!hasChildElements) {
            result.put(currentPrefix, element.getTextContent().trim());
        }

        return result;
    }

    private String extractAttribute(Element element, String... attributeNames) {
        for (String name : attributeNames) {
            if (element.hasAttribute(name)) {
                return element.getAttribute(name);
            }
        }
        // Try child elements
        for (String name : attributeNames) {
            NodeList nodes = element.getElementsByTagName(name);
            if (nodes.getLength() > 0) {
                return nodes.item(0).getTextContent().trim();
            }
        }
        return UUID.randomUUID().toString();
    }

    private Map<String, String> extractFlatRecord(Element element) {
        Map<String, String> record = new LinkedHashMap<>();
        NamedNodeMap attrs = element.getAttributes();
        for (int i = 0; i < attrs.getLength(); i++) {
            Attr attr = (Attr) attrs.item(i);
            record.put(attr.getName(), attr.getValue());
        }
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                String key = child.getLocalName() != null ? child.getLocalName() : child.getNodeName();
                record.put(key, child.getTextContent().trim());
            }
        }
        return record;
    }

    // --- Processing Logic ---
    private BatchResult processBatch(List<DataEntity> batch, int batchNumber, ImportJob job) {
        LOGGER.info("Processing batch #" + batchNumber + " with " + batch.size() + " entities");
        BatchResult result = new BatchResult();

        for (DataEntity entity : batch) {
            try {
                validateEntity(entity);
                transformEntity(entity);
                persistEntity(entity);
                result.successCount++;
                job.incrementProcessed();
            } catch (Exception e) {
                result.failCount++;
                result.errors.add("Entity " + entity.getId() + ": " + e.getMessage());
                job.incrementFailed();
            }
        }

        LOGGER.info("Batch #" + batchNumber + " completed: " + result.successCount + " success, " + result.failCount + " failures");
        return result;
    }

    private void validateEntity(DataEntity entity) throws ValidationException {
        if (entity.getType() == null || entity.getType().isEmpty()) {
            throw new ValidationException("Entity type is required");
        }
        if (entity.getId() == null || entity.getId().isEmpty()) {
            throw new ValidationException("Entity ID is required");
        }
        // Validate required properties based on entity type
        Map<String, List<String>> requiredFields = new HashMap<>();
        requiredFields.put("Customer", Arrays.asList("name"));
        requiredFields.put("Order", Arrays.asList("customerId", "date"));
        requiredFields.put("Product", Arrays.asList("name", "sku"));

        List<String> required = requiredFields.get(entity.getType());
        if (required != null) {
            for (String field : required) {
                if (!entity.getProperties().containsKey(field) ||
                        entity.getProperties().get(field).isEmpty()) {
                    throw new ValidationException("Required field missing: " + field);
                }
            }
        }
    }

    private void transformEntity(DataEntity entity) {
        // Apply business transformations
        Map<String, String> transformed = new LinkedHashMap<>();
        for (Map.Entry<String, String> entry : entity.getProperties().entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            // Normalize field names
            key = key.replaceAll("([a-z])([A-Z])", "$1_$2").toLowerCase();

            // Trim whitespace
            value = value.trim();

            // Date normalization (simple example)
            if (key.contains("date") && value.matches("\\d{2}/\\d{2}/\\d{4}")) {
                String[] parts = value.split("/");
                value = parts[2] + "-" + parts[0] + "-" + parts[1];
            }

            transformed.put(key, value);
        }
        entity.setProperties(transformed);

        // Add metadata
        entity.addProperty("_importTimestamp", String.valueOf(System.currentTimeMillis()));
        entity.addProperty("_entityType", entity.getType());
    }

